import { Injectable } from '@nestjs/common';
import type { CheckoutCompletedEventPayload } from '@smartcart/shared-types';
import { AnalyticsQueueProducer } from '../../../../infrastructure/messaging/analytics-queue.producer';
import type { IEventPublisher } from '../../application/interfaces/event-publisher.interface';

/**
 * BullMQ event publisher — the IEventPublisher port (README §2.8 Workflow 1
 * step 5 / Workflow 2 step 1). Delegates the actual enqueue to the shared
 * `AnalyticsQueueProducer`. Invoked only AFTER the checkout transaction commits.
 */
@Injectable()
export class BullMqEventPublisher implements IEventPublisher {
  constructor(private readonly producer: AnalyticsQueueProducer) {}

  async publish(event: CheckoutCompletedEventPayload): Promise<void> {
    await this.producer.enqueueProfileUpdate(event);
  }
}
